start_cluster 3 0 {tags {external:skip cluster}} {
    set primary [Rn 0]

    test "CONFIG RESETSTAT resets cluster bus message stats" {
        # First, check that some cluster stats are present (they should be,
        # as the cluster bus is active between the 3 nodes.)
        set cluster_info [$primary CLUSTER INFO]
        assert {[string match "*cluster_stats_messages_sent:*" $cluster_info]}
